// Appwrite Function: daily-press-release
// Schedule: 17:00 UTC (11pm BD) every day
// Cascade: OpenRouter → Gemini → Groq
// Image: SVG with embedded letterhead JPG + text overlay → Appwrite Storage (fb_media)

const TIMEOUT_MS = 25000;
function abortSignal(ms) {
  return AbortSignal.timeout ? AbortSignal.timeout(ms) : undefined;
}

const TODAY_BD = () => {
  const d = new Date(new Date().toLocaleString('en-US', { timeZone: 'Asia/Dhaka' }));
  return {
    iso: d.toISOString().slice(0, 10),
    bn: d.toLocaleDateString('bn-BD', { year: 'numeric', month: 'long', day: 'numeric' }),
    slug: `auto-press-release-${d.toISOString().slice(0, 10)}`,
  };
};

const JOAF_SYSTEM = `তুমি JOAF (জুলাই অনলাইন অ্যাক্টিভিস্ট ফোরাম) এর মুখপাত্র। 
JOAF বাংলাদেশের জুলাই ২০২৪ গণঅভ্যুত্থান থেকে জন্ম নেওয়া একটি নাগরিক আন্দোলন সংগঠন।
JOAF এর দাবি: নেতাদের জবাবদিহিতা, শহিদদের ন্যায়বিচার, গণতান্ত্রিক সংস্কার, দুর্নীতিমুক্ত বাংলাদেশ, সাধারণ মানুষের অধিকার।
তুমি সর্বদা আনুষ্ঠানিক বাংলায় লিখবে। সুর দৃঢ়, নাগরিক, দলনিরপেক্ষ।`;

const PRESS_PROMPT = (date) => `আজ ${date} তারিখে বাংলাদেশের বর্তমান পরিস্থিতি বিশ্লেষণ করে JOAF এর পক্ষে একটি দৈনিক প্রেস ব্রিফিং লেখো।

ফরম্যাট (JSON, অন্য কিছু না):
{
  "title": "আজকের মূল বিষয় সংক্ষেপে (৫-১০ শব্দ, তারিখ ছাড়া)",
  "summary": "এক বাক্যে মূল বার্তা (৩০ শব্দের মধ্যে)",
  "paragraphs": ["প্যারাগ্রাফ ১ (plain text, ৩-৪ বাক্য)", "প্যারাগ্রাফ ২", "প্যারাগ্রাফ ৩", "প্যারাগ্রাফ ৪ (জনগণের প্রতি আহ্বান)"]
}

গুরুত্বপূর্ণ: title-এ কোনো তারিখ বা "প্রেস ব্রিফিং" শব্দ রাখবে না। শুধু বিষয় লিখবে।
প্রতিটি paragraphs entry: plain text, কোনো HTML নয়।
শেষ paragraph এ থাকবে: "জুলাই অনলাইন অ্যাক্টিভিস্ট ফোরাম (JOAF)" বাক্য।
শুধু JSON রিটার্ন করো।`;

// ── Background image (base64 embedded — self-contained SVG) ──────────────────
const BG_DATA_URI = 'data:image/jpeg;base64,';

// ── SVG builder ───────────────────────────────────────────────────────────────
function escSVG(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

// Word-wrap Bengali text to lines of maxChars
function wrapBengali(text, maxChars) {
  const words = text.split(' ');
  const lines = [];
  let cur = '';
  for (const word of words) {
    const test = cur ? cur + ' ' + word : word;
    if (test.length > maxChars && cur) { lines.push(cur); cur = word; }
    else cur = test;
  }
  if (cur) lines.push(cur);
  return lines;
}

function buildSVG({ title, date, paragraphs }) {
  // Letterhead canvas: 1414 x 2000 (exact bg image size)
  const W = 1414, H = 2000;
  const FONT = "'Noto Sans Bengali', Arial, sans-serif";
  const TEXT_X = 110;       // left margin
  const TEXT_RIGHT = 1304;  // right margin (W - 110)
  const MAX_CHARS = 54;     // chars per line at font-size 38
  const LINE_H = 58;        // line height px
  const PARA_GAP = 36;      // extra gap between paragraphs
  const TITLE_Y = 345;      // title baseline
  const BODY_START_Y = 430; // first body line baseline (date removed, gap reduced)
  const MAX_BODY_BOTTOM = 1520; // don't go below signatures

  // Build all body lines
  const allBlocks = []; // [{lines, isLast}]
  for (let i = 0; i < paragraphs.length; i++) {
    allBlocks.push({
      lines: wrapBengali(paragraphs[i], MAX_CHARS),
      isLast: i === paragraphs.length - 1,
    });
  }

  // Render text elements
  let textEls = '';
  let y = BODY_START_Y;
  for (const block of allBlocks) {
    if (y > MAX_BODY_BOTTOM) break;
    for (const line of block.lines) {
      if (y > MAX_BODY_BOTTOM) break;
      const fill = block.isLast ? '#5c2a0e' : '#1a0f00';
      const fw = block.isLast ? '700' : '400';
      textEls += `<text x="${TEXT_X}" y="${y}" font-family="${FONT}" font-size="38" fill="${fill}" font-weight="${fw}">${escSVG(line)}</text>\n`;
      y += LINE_H;
    }
    y += PARA_GAP;
  }

  return `<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" viewBox="0 0 ${W} ${H}" preserveAspectRatio="xMidYMid meet">
  <defs>
    <style>@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+Bengali:wght@400;600;700&amp;display=swap');</style>
  </defs>

  <!-- Letterhead background (embedded) -->
  <image href="${BG_DATA_URI}" x="0" y="0" width="${W}" height="${H}" preserveAspectRatio="xMidYMid meet"/>

  <!-- Title -->
  <text x="${W / 2}" y="${TITLE_Y}" font-family="${FONT}" font-size="52" fill="#5c2a0e" text-anchor="middle" font-weight="700">${escSVG(title)}</text>


  <!-- Thin divider line -->
  <line x1="${TEXT_X}" y1="${BODY_START_Y - 28}" x2="${TEXT_RIGHT}" y2="${BODY_START_Y - 28}" stroke="#8B4513" stroke-width="1.5" stroke-dasharray="8,5"/>

  <!-- Body text -->
  ${textEls}
</svg>`;
}

// ── AI Providers ──────────────────────────────────────────────────────────────
async function callAI(providers, date) {
  const messages = [
    { role: 'system', content: JOAF_SYSTEM },
    { role: 'user', content: PRESS_PROMPT(date) },
  ];
  for (const { name, fn } of providers) {
    try {
      const text = await fn(messages);
      const clean = text.replace(/```json|```/g, '').trim();
      // Extract JSON object robustly
      const jsonMatch = clean.match(/\{[\s\S]*\}/);
      if (!jsonMatch) throw new Error('no JSON object found');
      // Sanitize: replace unescaped newlines/tabs inside strings
      let s = jsonMatch[0], out = '', inStr2 = false;
      for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (c === '\\' && inStr2) { out += c + (s[i+1]||''); i++; continue; }
        if (c === '"') { inStr2 = !inStr2; out += c; continue; }
        if (inStr2 && (c === '\n' || c === '\r')) { out += ' '; continue; }
        if (inStr2 && c === '\t') { out += ' '; continue; }
        out += c;
      }
      const parsed = JSON.parse(out);
      if (parsed.title && parsed.paragraphs?.length) {
        parsed.summary = parsed.summary || parsed.paragraphs[0].slice(0, 80);
        console.log(`daily-press-release: ${name} OK`);
        return parsed;
      }
      throw new Error('invalid structure');
    } catch (e) {
      console.log(`daily-press-release: ${name} failed — ${e.message}`);
    }
  }
  throw new Error('All AI providers failed');
}

async function openRouter(key, messages) {
  const res = await fetch('https://openrouter.ai/api/v1/chat/completions', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key, 'HTTP-Referer': 'https://julyforum.com', 'X-Title': 'JOAF' },
    body: JSON.stringify({ model: 'meta-llama/llama-3.3-70b-instruct:free', max_tokens: 1200, temperature: 0.7, messages }),
    signal: abortSignal(TIMEOUT_MS),
  });
  if (!res.ok) throw new Error('OR:' + res.status);
  return (await res.json()).choices[0].message.content;
}

async function gemini(key, messages) {
  const contents = messages.filter(m => m.role !== 'system').map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }],
  }));
  const sys = messages.find(m => m.role === 'system');
  if (sys && contents[0]) contents[0].parts.unshift({ text: '[SYSTEM]\n' + sys.content + '\n\n' });
  const res = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${key}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ contents, generationConfig: { maxOutputTokens: 1200, temperature: 0.7 } }),
    signal: abortSignal(TIMEOUT_MS),
  });
  if (!res.ok) throw new Error('Gemini:' + res.status);
  const d = await res.json();
  return d.candidates?.flatMap(c => c.content?.parts || []).map(p => p.text || '').join('');
}

async function groq(key, messages) {
  const res = await fetch('https://api.groq.com/openai/v1/chat/completions', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + key },
    body: JSON.stringify({ model: 'llama-3.3-70b-versatile', max_tokens: 1200, temperature: 0.7, messages }),
    signal: abortSignal(TIMEOUT_MS),
  });
  const d = await res.json();
  if (!res.ok) throw new Error(JSON.stringify(d.error || res.status));
  return d.choices[0].message.content;
}

// ── Upload SVG to Appwrite Storage + Cloudinary JPG ─────────────────────────
async function uploadImageToAppwriteStorage({ svgContent, slug, ep, pj }) {
  const svgBuffer = Buffer.from(svgContent, 'utf8');
  const filename = `${slug}.svg`;

  // 1) Upload SVG to Appwrite (for website display)
  const form = new FormData();
  form.append('fileId', 'unique()');
  form.append('file', new Blob([svgBuffer], { type: 'image/svg+xml' }), filename);

  const uploadRes = await fetch(`${ep}/storage/buckets/fb_media/files`, {
    method: 'POST',
    headers: {
      'X-Appwrite-Project': pj,
      'X-Appwrite-Key': process.env.APPWRITE_API_KEY || process.env.AW_KEY || '',
    },
    body: form,
    signal: abortSignal(22000),
  });

  if (!uploadRes.ok) throw new Error('Appwrite Storage upload failed: ' + uploadRes.status + ' ' + await uploadRes.text());
  const data = await uploadRes.json();
  const svgUrl = `${ep}/storage/buckets/fb_media/files/${data.$id}/view?project=${pj}`;

  // 2) Upload SVG to Cloudinary → auto-converts to JPG (for Facebook)
  let jpgUrl = svgUrl; // fallback
  try {
    const CLOUD_NAME = 'dou71pfe1';
const CDN_API_KEY  = process.env.CLOUDINARY_API_KEY    || '';
const CDN_API_SEC  = process.env.CLOUDINARY_API_SECRET || '';
    const UPLOAD_PRESET = 'kf483px5';
    const cdnForm = new FormData();
    cdnForm.append('file', new Blob([svgBuffer], { type: 'image/svg+xml' }), filename);
    cdnForm.append('upload_preset', UPLOAD_PRESET);
    cdnForm.append('public_id', slug);
    
    const cdnRes = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/image/upload`, {
      method: 'POST',
      body: cdnForm,
      signal: abortSignal(25000),
    });
    if (cdnRes.ok) {
      const cdnData = await cdnRes.json();
      jpgUrl = (cdnData.secure_url || svgUrl).replace('/upload/', '/upload/f_jpg/');
    }
  } catch (e) {
    // Cloudinary failed, jpgUrl stays as svgUrl fallback
  }

  return { svgUrl, jpgUrl };
}

// ── Appwrite Save ─────────────────────────────────────────────────────────────
async function saveToAppwrite(doc) {
  const EP  = process.env.APPWRITE_ENDPOINT || 'https://fra.cloud.appwrite.io/v1';
  const PJ  = process.env.APPWRITE_PROJECT_ID || '6a11b6cd000b59f318eb';
  const DB  = process.env.APPWRITE_DATABASE_ID || 'joaf';
  const KEY = process.env.APPWRITE_API_KEY;

  const checkRes = await fetch(
    `${EP}/databases/${DB}/collections/press_releases/documents?queries[]=${encodeURIComponent(`equal("slug","${doc.slug}")`)}`,
    { headers: { 'X-Appwrite-Project': PJ, 'X-Appwrite-Key': KEY } }
  );
  const checkData = await checkRes.json();
  if (checkData.total > 0) { console.log('already exists, skipping'); return { skipped: true }; }

  const htmlContent = (doc.paragraphs || []).map(p => `<p>${p}</p>`).join('\n');

  const res = await fetch(`${EP}/databases/${DB}/collections/press_releases/documents`, {
    method: 'POST',
    headers: { 'X-Appwrite-Project': PJ, 'X-Appwrite-Key': KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      documentId: 'unique()',
      data: {
        title: doc.title,
        summary: doc.summary,
        content: htmlContent,
        body: htmlContent,
        date: doc.date,
        slug: doc.slug,
        img: doc.svgUrl || '/img/press-release-bg.jpg',
        imageUrl: doc.jpgUrl || '',
        published: true,
        createdAt: new Date().toISOString(),
      },
    }),
  });
  if (!res.ok) throw new Error('Appwrite save failed: ' + await res.text());
  return res.json();
}

// ── Main ──────────────────────────────────────────────────────────────────────
export default async ({ req, res, log, error }) => {
  const { iso, bn, slug } = TODAY_BD();
  log('daily-press-release: running for ' + iso);

  const OR_KEY     = process.env.OPENROUTER_API_KEY;
  const GEMINI_KEY = process.env.GEMINI_API_KEY;
  const GROQ_KEY   = process.env.GROQ_API_KEY;
  const ADMIN_KEY  = process.env.ADMIN_SECRET_KEY || '';
  const EP         = process.env.APPWRITE_ENDPOINT || 'https://fra.cloud.appwrite.io/v1';
  const PJ         = process.env.APPWRITE_PROJECT_ID || '6a11b6cd000b59f318eb';

  const providers = [
    OR_KEY     && { name: 'OpenRouter', fn: (m) => openRouter(OR_KEY, m) },
    GEMINI_KEY && { name: 'Gemini',     fn: (m) => gemini(GEMINI_KEY, m) },
    GROQ_KEY   && { name: 'Groq',       fn: (m) => groq(GROQ_KEY, m) },
  ].filter(Boolean);

  if (!providers.length) return res.json({ error: 'No AI provider configured' }, 500);

  try {
    // 1. Generate text
    const generated = await callAI(providers, bn);

    // 2. Build SVG + upload to GitHub
    let svgUrl = '/img/press-release-bg.jpg';
    let jpgUrl = '';
    try {
      const svgContent = buildSVG({ title: generated.title, date: bn, paragraphs: generated.paragraphs });
      const urls = await uploadImageToAppwriteStorage({ svgContent, slug, ep: EP, pj: PJ });
      svgUrl = urls.svgUrl;
      jpgUrl = urls.jpgUrl;
      log('daily-press-release: image → ' + svgUrl);
    } catch (imgErr) {
      error('daily-press-release: image generation skipped — ' + imgErr.message);
    }

    // 3. Save to Appwrite
    const saved = await saveToAppwrite({ ...generated, date: iso, slug, svgUrl, jpgUrl });
    log('daily-press-release: ' + (saved.skipped ? 'skipped (exists)' : 'saved ' + saved.$id));

    // Auto-post to FB if not skipped
    let fbResult = null;
    if (!saved.skipped && jpgUrl) {
      try {
        const fbPayload = {
          async: false, path: '/', method: 'POST', headers: {},
          body: JSON.stringify({
            action: 'post',
            imageUrl: jpgUrl,
            caption: `📋 আজকের JOAF প্রেস ব্রিফিং\n\n${generated.title}\n\n${generated.summary}\n\nবিস্তারিত পড়ুন: https://julyforum.com/press-releases/view.html?id=${saved.$id}\n\n#JOAF #জুলাইফোরাম #বাংলাদেশ`,
          })
        };
        const execRes = await fetch(`${EP}/functions/fb-autopost/executions`, {
          method: 'POST',
          headers: { 'X-Appwrite-Project': PJ, 'X-Appwrite-Key': process.env.APPWRITE_API_KEY || process.env.AW_KEY || '', 'Content-Type': 'application/json' },
          body: JSON.stringify(fbPayload),
          signal: abortSignal(90000),
        });
        if (execRes.ok) {
          const execData = await execRes.json();
          const rb = execData.responseBody || execData.body || '{}';
          fbResult = typeof rb === 'string' ? JSON.parse(rb) : rb;
          log('daily-press-release: fb-autopost → ok=' + fbResult.ok + ' pages=' + (fbResult.ok || 0));
        }
      } catch (fbErr) {
        error('daily-press-release: fb-autopost failed — ' + fbErr.message);
      }
    }

    // files kept in Appwrite + Cloudinary for website display

    return res.json({ ok: true, date: iso, skipped: saved.skipped || false, id: saved.$id, img: svgUrl, fbImg: jpgUrl, fb: fbResult });
  } catch (e) {
    error('daily-press-release: ' + e.message);
    throw e; // let retry loop handle it
  }
};
